import React, { useState } from 'react';
import { downloadFile } from '../../utils/downloadHelper';
import { generateCode } from '../../utils/codeGenerator';
import { WindowPanel as WindowPanelType, BackgroundConfig, DataConnection, CodeEditorConfig } from '../../types';

interface ExportManagerProps {
    windows: WindowPanelType[];
    backgroundConfig: BackgroundConfig;
    onBackgroundConfigChange: (config: BackgroundConfig) => void;
    dataConnections?: DataConnection;
    onWindowsChange?: (windows: WindowPanelType[]) => void;
    onDataConnectionsChange?: (dataConnections: DataConnection) => void;
    codeEditorConfigs?: CodeEditorConfig[];
    onCodeEditorConfigsChange?: (configs: CodeEditorConfig[]) => void;
}

const ExportManager: React.FC<ExportManagerProps> = ({ 
    windows, 
    backgroundConfig, 
    onBackgroundConfigChange, 
    dataConnections = { apiConnections: [], globalVariables: {} },
    onWindowsChange,
    onDataConnectionsChange
}) => {
    const [exportFormat, setExportFormat] = useState<'html' | 'js' | 'json'>('html');
    const [isExportExpanded, setIsExportExpanded] = useState(true);
    const [isImportExpanded, setIsImportExpanded] = useState(false);

    const transformWindowsForExport = (windows: WindowPanelType[]) => {
        return windows.map(window => {
            if (window.type === 'visualization' && window.content && window.content.startsWith('IMAGE:')) {
                // Transform media content for better JSON readability
                const parts = window.content.split(':');
                const fileName = parts[1] || 'image';
                const dataUrl = parts.slice(2).join(':');

                // Extract file type from data URL
                const fileTypeMatch = dataUrl.match(/^data:([^;]+);/);
                const fileType = fileTypeMatch ? fileTypeMatch[1] : 'image/png';

                return {
                    ...window,
                    content: '',  // Clear the content to avoid huge JSON
                    mediaInfo: {
                        type: 'image',
                        fileName: fileName,
                        fileType: fileType,
                        hasData: true,
                        note: 'Image data excluded from JSON export for readability. Use HTML export to preserve images.'
                    }
                };
            }
            return window;
        });
    };

    const handleExport = () => {
        switch (exportFormat) {
            case 'html':
                const htmlCode = generateCode(windows, 'html', backgroundConfig, dataConnections);
                downloadFile('website.html', htmlCode);
                break;
            case 'js':
                const jsCode = generateCode(windows, 'js', backgroundConfig, dataConnections);
                downloadFile('website.js', jsCode);
                break;
            case 'json':
                const transformedWindows = transformWindowsForExport(windows);
                const jsonCode = JSON.stringify({ windows: transformedWindows, backgroundConfig, dataConnections }, null, 2);
                downloadFile('website-config.json', jsonCode);
                break;
        }
    };

    const previewCode = () => {
        const code = generateCode(windows, exportFormat, exportFormat === 'html' ? backgroundConfig : undefined);
        const previewWindow = window.open('', '_blank');
        if (previewWindow) {
            if (exportFormat === 'html') {
                previewWindow.document.write(code);
            } else {
                previewWindow.document.write(`
                    <html>
                        <head><title>Code Preview</title></head>
                        <body>
                            <pre style="background: #f5f5f5; padding: 20px; font-family: monospace; white-space: pre-wrap;">${code.replace(/</g, '&lt;').replace(/>/g, '&gt;')}</pre>
                        </body>
                    </html>
                `);
            }
        }
    };

    const handleImport = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const result = e.target && e.target.result;
                if (!result || typeof result !== 'string') return;
                const content = result;
                const config = JSON.parse(content);

                // Validate the configuration structure
                if (config.windows && Array.isArray(config.windows)) {
                    if (onWindowsChange) {
                        onWindowsChange(config.windows);
                    }
                }

                if (config.backgroundConfig) {
                    onBackgroundConfigChange(config.backgroundConfig);
                }

                if (config.dataConnections && onDataConnectionsChange) {
                    onDataConnectionsChange(config.dataConnections);
                }

                alert('Configuration imported successfully!');
            } catch (error) {
                alert('Error importing configuration: Invalid JSON file');
                console.error('Import error:', error);
            }
        };
        reader.readAsText(file);

        // Reset the input value so the same file can be imported again
        event.target.value = '';
    };

    return (
        <div style={{ 
            padding: '15px', 
            backgroundColor: 'white', 
            borderLeft: '1px solid #dee2e6',
            height: '100%',
            overflow: 'auto'
        }}>
            <h2 style={{ margin: '0 0 20px 0', fontSize: '18px' }}>Configuration Manager</h2>

            {/* Import Section */}
            <div style={{ marginBottom: '20px', border: '1px solid #dee2e6', borderRadius: '4px' }}>
                <div 
                    style={{ 
                        padding: '12px 15px', 
                        backgroundColor: '#f8f9fa', 
                        borderBottom: isImportExpanded ? '1px solid #dee2e6' : 'none',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between'
                    }}
                    onClick={() => setIsImportExpanded(!isImportExpanded)}
                >
                    <h3 style={{ margin: 0, fontSize: '16px', color: '#28a745' }}>📥 Import Configuration</h3>
                    <span style={{ fontSize: '14px' }}>{isImportExpanded ? '▼' : '▶'}</span>
                </div>

                {isImportExpanded && (
                    <div style={{ padding: '15px' }}>
                        <p style={{ margin: '0 0 15px 0', fontSize: '14px', color: '#6c757d' }}>
                            Import a previously exported JSON configuration file to restore windows, background settings, and data connections.
                        </p>

                        <input
                            type="file"
                            accept=".json,application/json"
                            onChange={handleImport}
                            style={{
                                width: '100%',
                                padding: '8px',
                                border: '1px solid #dee2e6',
                                borderRadius: '4px',
                                fontSize: '14px',
                                cursor: 'pointer'
                            }}
                        />

                        <div style={{ 
                            marginTop: '10px', 
                            padding: '10px', 
                            backgroundColor: '#fff3cd', 
                            borderRadius: '4px',
                            fontSize: '12px',
                            color: '#856404'
                        }}>
                            ⚠️ Importing will replace your current configuration. Make sure to export your current work first!
                        </div>
                    </div>
                )}
            </div>

            {/* Export Section */}
            <div style={{ marginBottom: '20px', border: '1px solid #dee2e6', borderRadius: '4px' }}>
                <div 
                    style={{ 
                        padding: '12px 15px', 
                        backgroundColor: '#f8f9fa', 
                        borderBottom: isExportExpanded ? '1px solid #dee2e6' : 'none',
                        cursor: 'pointer',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between'
                    }}
                    onClick={() => setIsExportExpanded(!isExportExpanded)}
                >
                    <h3 style={{ margin: 0, fontSize: '16px', color: '#0066cc' }}>📤 Export Configuration</h3>
                    <span style={{ fontSize: '14px' }}>{isExportExpanded ? '▼' : '▶'}</span>
                </div>

                {isExportExpanded && (
                    <div style={{ padding: '15px' }}>

            {/* Background Configuration */}
            <div style={{ marginBottom: '20px', padding: '15px', backgroundColor: '#f8f9fa', borderRadius: '4px' }}>
                <h4 style={{ margin: '0 0 15px 0', fontSize: '14px', color: '#495057' }}>Background Settings</h4>

                <div style={{ marginBottom: '10px' }}>
                    <label style={{ display: 'block', marginBottom: '4px', fontSize: '12px', fontWeight: 'bold' }}>
                        Width (px):
                    </label>
                    <input
                        type="number"
                        value={backgroundConfig.width}
                        onChange={(e) => onBackgroundConfigChange({
                            ...backgroundConfig,
                            width: parseInt(e.target.value) || 1200
                        })}
                        style={{
                            width: '100%',
                            padding: '4px 8px',
                            border: '1px solid #dee2e6',
                            borderRadius: '4px',
                            fontSize: '12px'
                        }}
                    />
                </div>

                <div style={{ marginBottom: '10px' }}>
                    <label style={{ display: 'block', marginBottom: '4px', fontSize: '12px', fontWeight: 'bold' }}>
                        Height (px):
                    </label>
                    <input
                        type="number"
                        value={backgroundConfig.height}
                        onChange={(e) => onBackgroundConfigChange({
                            ...backgroundConfig,
                            height: parseInt(e.target.value) || 800
                        })}
                        style={{
                            width: '100%',
                            padding: '4px 8px',
                            border: '1px solid #dee2e6',
                            borderRadius: '4px',
                            fontSize: '12px'
                        }}
                    />
                </div>

                <div style={{ marginBottom: '0' }}>
                    <label style={{ display: 'block', marginBottom: '4px', fontSize: '12px', fontWeight: 'bold' }}>
                        Background Color:
                    </label>
                    <input
                        type="color"
                        value={backgroundConfig.color}
                        onChange={(e) => onBackgroundConfigChange({
                            ...backgroundConfig,
                            color: e.target.value
                        })}
                        style={{
                            width: '100%',
                            height: '32px',
                            border: '1px solid #dee2e6',
                            borderRadius: '4px',
                            cursor: 'pointer'
                        }}
                    />
                </div>
            </div>

            {/* Global Variables Display */}
            {dataConnections.apiConnections.length > 0 && (
                <div style={{ marginBottom: '20px', padding: '15px', backgroundColor: '#f0f8ff', borderRadius: '4px', border: '1px solid #b3d9ff' }}>
                    <h4 style={{ margin: '0 0 15px 0', fontSize: '14px', color: '#0066cc' }}>🔗 Available Global Variables</h4>
                    {dataConnections.apiConnections.map(api => (
                        <div key={api.id} style={{ marginBottom: '15px' }}>
                            <div style={{ fontSize: '12px', fontWeight: 'bold', color: '#0066cc', marginBottom: '5px' }}>
                                API: {api.name} ({api.method})
                            </div>
                            <div style={{ fontSize: '11px', fontFamily: 'monospace', backgroundColor: '#ffffff', padding: '8px', borderRadius: '3px', border: '1px solid #dee2e6' }}>
                                <div style={{ marginBottom: '4px', color: '#28a745' }}>
                                    // Call this API:<br/>
                                    <strong>await fetch{api.name.replace(/[^a-zA-Z0-9]/g, '')}()</strong>
                                </div>
                                {api.variables.length > 0 && (
                                    <>
                                        <div style={{ marginBottom: '2px', color: '#6c757d' }}>// Available variables:</div>
                                        {api.variables.map(variable => (
                                            <div key={variable.id} style={{ color: '#dc3545' }}>
                                                <strong>{variable.name}</strong> ({variable.type})
                                                {variable.description && <span style={{ color: '#6c757d' }}> - {variable.description}</span>}
                                            </div>
                                        ))}
                                    </>
                                )}
                            </div>
                        </div>
                    ))}
                    <div style={{ fontSize: '11px', color: '#6c757d', fontStyle: 'italic' }}>
                        💡 Use these variables in your JavaScript and HTML windows after calling the API functions
                    </div>
                </div>
            )}

            <div style={{ marginBottom: '20px' }}>
                <label style={{ 
                    display: 'block', 
                    marginBottom: '8px', 
                    fontSize: '14px', 
                    fontWeight: 'bold' 
                }}>
                    Export Format:
                </label>
                <select 
                    value={exportFormat}
                    onChange={(e) => {
                        const value = e.target.value;
                        if (value === 'html' || value === 'js' || value === 'json') {
                            setExportFormat(value);
                        }
                    }}
                    style={{
                        width: '100%',
                        padding: '8px',
                        border: '1px solid #dee2e6',
                        borderRadius: '4px',
                        fontSize: '14px'
                    }}
                >
                    <option value="html">Complete HTML Page</option>
                    <option value="js">JavaScript Code Only</option>
                    <option value="json">Configuration JSON</option>
                </select>
            </div>

            <div style={{ marginBottom: '20px' }}>
                <button 
                    onClick={handleExport}
                    disabled={windows.length === 0}
                    style={{
                        width: '100%',
                        padding: '12px',
                        backgroundColor: windows.length === 0 ? '#6c757d' : '#28a745',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: windows.length === 0 ? 'not-allowed' : 'pointer',
                        fontSize: '14px',
                        fontWeight: 'bold',
                        marginBottom: '10px'
                    }}
                >
                    Download {exportFormat.toUpperCase()}
                </button>

                <button 
                    onClick={previewCode}
                    disabled={windows.length === 0}
                    style={{
                        width: '100%',
                        padding: '8px',
                        backgroundColor: windows.length === 0 ? '#6c757d' : '#007bff',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: windows.length === 0 ? 'not-allowed' : 'pointer',
                        fontSize: '12px'
                    }}
                >
                    Preview Code
                </button>
            </div>

            <div style={{ 
                padding: '15px', 
                backgroundColor: '#f8f9fa', 
                borderRadius: '4px',
                fontSize: '12px'
            }}>
                <h4 style={{ margin: '0 0 10px 0', fontSize: '14px' }}>Export Info:</h4>
                <p style={{ margin: '5px 0' }}>Windows: {windows.length}</p>
                <p style={{ margin: '5px 0' }}>
                    JavaScript Windows: {windows.filter(w => w.type === 'javascript').length}
                </p>
                <p style={{ margin: '5px 0' }}>
                    HTML Windows: {windows.filter(w => w.type === 'html').length}
                </p>
                <p style={{ margin: '5px 0' }}>
                    Visualization Windows: {windows.filter(w => w.type === 'visualization').length}
                </p>
            </div>

                        {windows.length === 0 && (
                            <div style={{ 
                                marginTop: '20px', 
                                padding: '15px', 
                                backgroundColor: '#fff3cd', 
                                borderRadius: '4px',
                                fontSize: '12px',
                                color: '#856404'
                            }}>
                                ⚠️ Add some windows to your canvas before exporting
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

export default ExportManager;
